131	  //----------------------------------------------------------------
132	  // dump_dut_state()
133	  //
134	  // Dump the state of the dump when needed.
135	  //----------------------------------------------------------------
136	  task dump_dut_state;
137	    begin
138	      $display("cycle: 0x%016x", cycle_ctr);
139	      $display("State of DUT");
140	      $display("------------");
141	      $display("ctrl_reg:   init   = 0x%01x, next   = 0x%01x", dut.init_reg, dut.next_reg);
142	      $display("config_reg: encdec = 0x%01x, length = 0x%01x ", dut.encdec_reg, dut.keylen_reg);
143	      $display("");
144	
145	      $display("block: 0x%08x, 0x%08x, 0x%08x, 0x%08x",
146	               dut.block_reg[0], dut.block_reg[1], dut.block_reg[2], dut.block_reg[3]);
147	      $display("");
148	
149	    end
150	  endtask // dump_dut_state
